#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <math.h>
#include <time.h>
#include <stdint.h>
#include <stdbool.h>
typedef struct { int x1, y1, x2, y2; } rect;
int compare(const void *a, const void *b) {
    rect *r1 = (rect *)a;
    rect *r2 = (rect *)b;
    if (r1->x2 != r2->x2) return r1->x2 - r2->x2;
    return r1->y2 - r2->y2;
}
int maxPaintedRectangles(rect *rectangles, int n) {
    qsort(rectangles, n, sizeof(rect), compare);
    int maxPainted = 0, currY = -1000000001;
    for (int i = 0; i < n; i++) {
        if (rectangles[i].y1 > currY) {
            maxPainted++;
            currY = rectangles[i].y2;
        }
    }
    return maxPainted;
}
int main() {
    int n;
    scanf("%d", &n);
    rect *rectangles = (rect *)malloc(n * sizeof(rect));
    for (int i = 0; i < n; i++) {
        scanf("%d %d %d %d", &rectangles[i].x1, &rectangles[i].y1, &rectangles[i].x2, &rectangles[i].y2);
    }
    printf("%d\n", maxPaintedRectangles(rectangles, n));
    free(rectangles);
    return 0;
}

