import java.util.Arrays;
import java.util.Scanner;
class rect implements Comparable<rect> {
    int x1, y1, x2, y2;
    rect(int x1, int y1, int x2, int y2) {
        this.x1 = x1;
        this.y1 = y1;
        this.x2 = x2;
        this.y2 = y2;
    }
    public int compareTo(rect other) {
        if (this.x2 != other.x2) return Integer.compare(this.x2, other.x2);
        return Integer.compare(this.y2, other.y2);
    }
}
public class Main {
    public static int maxPaintedRectangles(rect[] rectangles) {
        Arrays.sort(rectangles);
        int maxPainted = 0, currY = -1000000001;
        for (rect r : rectangles) {
            if (r.y1 > currY) {
                maxPainted++;
                currY = r.y2;
            }
        }
        return maxPainted;
    }
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int n = scanner.nextInt();
        rect[] rectangles = new rect[n];
        for (int i = 0; i < n; i++) {
            int x1 = scanner.nextInt(), y1 = scanner.nextInt(), x2 = scanner.nextInt(), y2 = scanner.nextInt();
            rectangles[i] = new rect(x1, y1, x2, y2);
        }
        System.out.println(maxPaintedRectangles(rectangles));
    }
}

