class rect:
    def __init__(self, x1, y1, x2, y2):
        self.x1 = x1
        self.y1 = y1
        self.x2 = x2
        self.y2 = y2

def max_painted_rectangles(rectangles):
    rectangles.sort(key=lambda r: (r.x2, r.y2))
    max_painted = 0
    curr_y = -1000000001
    for r in rectangles:
        if r.y1 > curr_y:
            max_painted += 1
            curr_y = r.y2
    return max_painted

def main():
    n = int(input())
    rectangles = []
    for _ in range(n):
        x1, y1, x2, y2 = map(int, input().split())
        rectangles.append(rect(x1, y1, x2, y2))
    print(max_painted_rectangles(rectangles))

def test():
    assert max_painted_rectangles([rect(0, 0, 1, 1), rect(1, 1, 2, 2)]) == 2
    assert max_painted_rectangles([rect(0, 0, 2, 2), rect(1, 1, 3, 3)]) == 2
    assert max_painted_rectangles([rect(-1, -1, 0, 0), rect(0, 0, 1, 1)]) == 2
